proof fn phi_1_temp_pred_equality_intensional_bridge(p: TempPred<int>, q: TempPred<int>)
    requires
        p.entails(q),
        q.entails(p),
    ensures
        p == q,
{
    temp_pred_equality::<int>(p, q);
}

proof fn phi_2_always_and_equality_intensional_bridge(p: TempPred<int>, q: TempPred<int>)
    ensures
        always(p.and(q)) == always(p).and(always(q)),
{
    always_and_equality::<int>(p, q);
}

proof fn phi_3_entails_and_temp_closure_bridge(spec: TempPred<int>, p: TempPred<int>, q: TempPred<int>)
    requires
        spec.entails(p),
        spec.entails(q),
    ensures
        spec.entails(p.and(q)),
{
    entails_and_temp::<int>(spec, p, q);
}

proof fn phi_4_mutual_entailment_derives_false_if_distinct(p: TempPred<int>, q: TempPred<int>)
    requires
        p.entails(q),
        q.entails(p),
        p !== q,
    ensures
        false,
{
    temp_pred_equality::<int>(p, q);
}
